-- Part 1: University-level data for Georg-August-Universität Göttingen
UPDATE public.universities SET
  website_url = 'https://www.uni-goettingen.de/en/',
  tuition_usd = 1007,
  overall_acceptance_rate = '15%',
  test_policy = 'Not applicable',
  deadline_calendar = 'Winter semester (Oct start): July 15; Summer semester (Apr start): January 15. International students apply via uni-assist portal (www.uni-assist.de). Restricted programs (Medicine, Dentistry, Pharmacy, Psychology) apply via hochschulstart.de. Early application strongly recommended for visa processing time.',
  financial_aid = 'No tuition fees; only semester contribution fee of €466.40 (Summer 2026) / €436.36 (Winter 2025/26) covering student services, public transport pass (Semesterticket), and administration. Deutschlandstipendium (€300/month merit-based, open to all nationalities); DAAD scholarships (various programs for international students); Lower Saxony Scholarship (€500–€1,000 for academic achievement); Göttingen International Scholarship; emergency financial aid via Studentenwerk. Blocked account of ~€11,904/year required for German student visa.'
WHERE name = 'Georg-August-Universität Göttingen';

