  ('Psychology (B.Sc.)', '8%', 'Highly competitive locally restricted admission (NC); German C1-C2 required (DSH-2 or TestDaF 4x4); apply via uni-assist portal; strong interest in empirical and quantitative methods required; program covers clinical, cognitive, and social psychology; one of Göttingen''s most competitive programs', 51, NULL, NULL, NULL, NULL, 1.5, 'A*AA', 37, NULL, NULL, NULL)
